                    best_global_move = ('m', src, i, tgt)

    # Try swaps between ANY pair of GPUs
    for g1 in range(gpu_num):
        for i, ma in enumerate(final_p[g1]):
            wa, sa = ma.req_rate / ma.slo, ma.model_size
            for g2 in range(g1 + 1, gpu_num):
                for j, mb in enumerate(final_p[g2]):
                    wb, sb = mb.req_rate / mb.slo, mb.model_size
                    new_g1_size = final_gs[g1] - sa + sb
                    new_g2_size = final_gs[g2] - sb + sa
                    if new_g1_size > GPU_MEM_SIZE or new_g2_size > GPU_MEM_SIZE:
                        continue
                    rem_g1 = GPU_MEM_SIZE - new_g1_size
                    rem_g2 = GPU_MEM_SIZE - new_g2_size
                    if rem_g1 <= 0 or rem_g2 <= 0:
                        continue
                    nw_g1 = final_gw[g1] - wa + wb
                    nw_g2 = final_gw[g2] - wb + wa
                    kv_g1 = nw_g1 / rem_g1 if nw_g1 > 0 else 0.0
                    kv_g2 = nw_g2 / rem_g2 if nw_g2 > 0 else 0.0
                    new_mk = max(kv_g1, kv_g2)
                    if new_mk >= best_global_mk:
                        continue
                    for g3 in range(gpu_num):
                        if g3 == g1 or g3 == g2:
                            continue
                        if kvprs[g3] > new_mk:
                            new_mk = kvprs[g3]
                            if new_mk >= best_global_mk:
                                break
                    if new_mk < best_global_mk - 1e-15:
                        best_global_mk = new_mk
                        best_global_move = ('s', g1, i, g2, j)

    if best_global_move is None:
        break

    if best_global_move[0] == 'm':
        _, src, i, tgt = best_global_move
        model = final_p[src].pop(i)
        final_p[tgt].append(model)
        mw = model.req_rate / model.slo
        ms = model.model_size
        final_gw[src] -= mw
        final_gs[src] -= ms
        final_gw[tgt] += mw
        final_gs[tgt] += ms
    else:
        _, g1, i, g2, j = best_global_move
        ma = final_p[g1][i]
        mb = final_p[g2][j]
        final_p[g1][i] = mb
        final_p[g2][j] = ma
        wa, sa = ma.req_rate / ma.slo, ma.model_size
        wb, sb = mb.req_rate / mb.slo, mb.model_size
        final_gw[g1] += wb - wa
        final_gs[g1] += sb - sa
        final_gw[g2] += wa - wb
        final_gs[g2] += sa - sb

update_best(final_p, final_gw, final_gs)

return best_placement
